use std::error::Error;

#[derive(Debug)]
enum DivideError {
    ZeroDivision,
}

impl Error for DivideError {}

impl std::fmt::Display for DivideError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", match self {
            DivideError::ZeroDivision => "Divide by zero",
        })
    }
}

fn divide(numerator: i32, denominator: i32) -> Result<i32, DivideError> {
    if denominator == 0 { Err(DivideError::ZeroDivision) } else { Ok(numerator / denominator) }
}

fn main() {
    let numerator = 10;
    let denominator = 0;

    match divide(numerator, denominator) {
        Ok(result) => println!("Result: {}
", result),
